	xChar := strconv.FormatInt(x, 10)

	// Condition 1: It contains at least one digit x
	containsX := false
	for _, char := range nStr {
		if string(char) == xChar {
			containsX = true
			break
		}
	}

	if !containsX {
		return false
	}

	// Condition 2: It does not start with digit x
	startsWithX := false
	if len(nStr) > 0 && string(nStr[0]) == xChar {
		startsWithX = true
	}

	// The number is "effective" if (Condition 1 is true) AND (Condition 2 is false)
	return containsX && !startsWithX
